#!/usr/bin/env python3
"""
Algorithmic Pricing -- One-click launcher
Economics of AI, London Business School

Run:  python3 run_app.py   (Mac)
      python  run_app.py   (Windows)
"""
import subprocess, sys, os, base64, io, zipfile

APP_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), "streamlit_app")
QLEARN_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), "qlearning")

APP_DATA = """
"""

def install_packages():
    required = ["streamlit", "numpy", "pandas", "matplotlib"]
    missing = []
    for pkg in required:
        try:
            __import__(pkg)
        except ImportError:
            missing.append(pkg)
    if missing:
        print(f"Installing {', '.join(missing)} (first time only)...")
        subprocess.check_call(
            [sys.executable, "-m", "pip", "install", "--quiet"] + missing
        )
        print("Done.")

def extract_app():
    if (os.path.isdir(APP_DIR) and os.path.isdir(QLEARN_DIR)
            and os.path.isfile(os.path.join(APP_DIR, "Welcome.py"))):
        return
    print("Extracting app files...")
    data = base64.b64decode(APP_DATA.strip())
    buf = io.BytesIO(data)
    dest = os.path.dirname(os.path.abspath(__file__))
    with zipfile.ZipFile(buf, "r") as zf:
        zf.extractall(dest)
    print("Done.")

def launch():
    welcome = os.path.join(APP_DIR, "Welcome.py")
    print("Launching app -- a browser window will open shortly...")
    subprocess.call([
        sys.executable, "-m", "streamlit", "run", welcome,
        "--server.headless", "false"
    ])

if __name__ == "__main__":
    install_packages()
    extract_app()
    launch()
